import React from "react";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom";  // Updated for React Router v6
import CourseList from "./components/CourseList";  // Make sure CourseList component is correct
import CourseDetail from "./components/CourseDetail";  // Make sure CourseDetail component is correct
import EnrollForm from "./components/EnrollForm";  // Make sure EnrollForm component is correct

function App() {
  return (
    <Router>
      <div>
        <h1>Welcome to EduQuest</h1>
        <Routes>  {/* Use Routes instead of Switch */}
          <Route path="/" element={<CourseList />} />
          <Route path="/courses/:id" element={<CourseDetail />} />
          <Route path="/courses/:id/enroll" element={<EnrollForm />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
